import React, { useState, useEffect } from 'react';
import axios from 'axios';

function EventList() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [newEvent, setNewEvent] = useState({ title: '', description: '', start_time: '', end_time: '' });
  const [alert, setAlert] = useState(null);

  useEffect(() => {
    axios.get('http://localhost:8000/api/events/')
      .then(response => {
        setEvents(response.data);
        setLoading(false);
      })
      .catch(error => {
        console.error('Ошибка загрузки данных', error);
        setLoading(false);
      });
  }, []);

  const handleCreateEvent = () => {
    if (!newEvent.title || !newEvent.description || !newEvent.start_time || !newEvent.end_time) {
      setAlert({ message: 'Все поля должны быть заполнены!', type: 'danger' });
      setTimeout(() => setAlert(null), 3000);
      return;
    }

    axios.post('http://localhost:8000/api/events/', newEvent)
      .then(response => {
        setEvents([...events, response.data]);
        setShowModal(false); // Закрываем модальное окно
        setNewEvent({ title: '', description: '', start_time: '', end_time: '' }); // Сбрасываем форму
        setAlert({ message: 'Мероприятие добавлено успешно!', type: 'success' });
        setTimeout(() => setAlert(null), 3000); // Убираем уведомление через 3 секунды
      })
      .catch(error => {
        console.error('Ошибка создания мероприятия', error);
        setAlert({ message: 'Ошибка при создании мероприятия.', type: 'danger' });
        setTimeout(() => setAlert(null), 3000);
      });
  };

  if (loading) return <div className="text-center mt-5">Загрузка...</div>;

  return (
    <div className="container mt-4">
      {/* Уведомление */}
      {alert && (
        <div className={`alert alert-${alert.type} position-fixed top-0 start-50 translate-middle-x mt-3`} 
             style={{ zIndex: 1051 }} role="alert">
          {alert.message}
        </div>
      )}

      <h2>Список мероприятий</h2>
      <button className="btn btn-success mb-3" onClick={() => setShowModal(true)}>Добавить мероприятие</button>

      <div className="row">
        {events.map(event => (
          <div key={event.id} className="col-md-4 mb-4">
            <div className="card">
              <img src="https://via.placeholder.com/150" className="card-img-top" alt="..." />
              <div className="card-body">
                <h5 className="card-title">{event.title}</h5>
                <p className="card-text">{event.description}</p>
                <p className="card-text">
                  <small className="text-muted">
                    {new Date(event.start_time).toLocaleString()} - {new Date(event.end_time).toLocaleString()}
                  </small>
                </p>
                <button className="btn btn-primary">Подробнее</button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Модальное окно для создания мероприятия */}
      {showModal && (
        <div className="modal fade show" tabIndex="-1" style={{ display: 'block', zIndex: 1050 }} aria-hidden="true">
          <div className="modal-dialog">
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title">Добавить новое мероприятие</h5>
                <button type="button" className="btn-close" onClick={() => setShowModal(false)} aria-label="Close"></button>
              </div>
              <div className="modal-body">
                <div className="mb-3">
                  <label htmlFor="title" className="form-label">Название</label>
                  <input
                    type="text"
                    className="form-control"
                    id="title"
                    value={newEvent.title}
                    onChange={(e) => setNewEvent({ ...newEvent, title: e.target.value })}
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="description" className="form-label">Описание</label>
                  <textarea
                    className="form-control"
                    id="description"
                    rows="3"
                    value={newEvent.description}
                    onChange={(e) => setNewEvent({ ...newEvent, description: e.target.value })}
                  ></textarea>
                </div>
                <div className="mb-3">
                  <label htmlFor="start_time" className="form-label">Дата начала</label>
                  <input
                    type="datetime-local"
                    className="form-control"
                    id="start_time"
                    value={newEvent.start_time}
                    onChange={(e) => setNewEvent({ ...newEvent, start_time: e.target.value })}
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="end_time" className="form-label">Дата окончания</label>
                  <input
                    type="datetime-local"
                    className="form-control"
                    id="end_time"
                    value={newEvent.end_time}
                    onChange={(e) => setNewEvent({ ...newEvent, end_time: e.target.value })}
                  />
                </div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-secondary" onClick={() => setShowModal(false)}>Закрыть</button>
                <button type="button" className="btn btn-primary" onClick={handleCreateEvent}>Сохранить</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default EventList;
